  ('dietitian-moex-03724', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '臺南市衛生局代謝症候群的防制工作，今年度共投入50萬的計畫經費，舉辦了12場篩檢活動，1,393名 民眾接受篩檢；辦理11場演講，共有居民500人參與。投入經費比去年少10萬，但受惠人數卻增加。 則該局的防制工作最符合下列何種評量指標？', '["效率（efficiency）", "效能（effectiveness）", "效果（effort）", "效力（efficacy）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:02+00:00", "source_pdf_sha1": "a25566c0cb68", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
